import React, { createContext, useState } from 'react'

export const AppContext = createContext()

export const AppProvider = ({ children }) => {
  const [comentarios, setComentarios] = useState([])

  const agregarComentario = (nombre, texto) => {
    const fecha = new Date()
    setComentarios(prev => [
      {
        id: Date.now(),
        nombre,
        texto,
        fecha: fecha.toLocaleString('es-AR')
      },
      ...prev
    ])
  }

  return (
    <AppContext.Provider value={{
      comentarios,
      agregarComentario
    }}>
      {children}
    </AppContext.Provider>
  )
}

import React, { createContext, useContext, useState, useEffect } from "react";

// Crear contexto
const AuthContext = createContext();

// Hook personalizado para acceder al contexto
export const useAuth = () => useContext(AuthContext);

// Proveedor global
export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [registeredUsers, setRegisteredUsers] = useState(() => {
    // Usuarios iniciales
    const initialUsers = [
      {
        username: "facu",
        password: "Admin123+",
        nombre: "Facundo",
        apellido: "Caceres",
        dni: "12898081",
        email: "admin@sistema.com",
        telefono: "",
        role: "admin",
        fechaRegistro: new Date().toISOString(),
      },
      {
        username: "juancho",
        password: "Admin124+",
        nombre: "Juan",
        apellido: "Pinto",
        dni: "12898081",
        email: "admin@sistema.com",
        telefono: "",
        role: "admin",
        fechaRegistro: new Date().toISOString(),
      },
    ];

    // Recuperar usuarios registrados de localStorage
    const savedUsers = localStorage.getItem("registeredUsers");
    return savedUsers ? JSON.parse(savedUsers) : initialUsers;
  });

  // Guardar usuarios en localStorage cuando cambien
  useEffect(() => {
    localStorage.setItem("registeredUsers", JSON.stringify(registeredUsers));
  }, [registeredUsers]);

  // Función de registro
  const register = (userData) => {
    // Verificar si el usuario ya existe
    const userExists = registeredUsers.some(
      (user) =>
        user.username === userData.username || user.email === userData.email
    );

    if (userExists) {
      return {
        success: false,
        message: "El usuario o email ya están registrados",
      };
    }

    // Verificar si el DNI ya existe
    const dniExists = registeredUsers.some((user) => user.dni === userData.dni);

    if (dniExists) {
      return { success: false, message: "El DNI ya está registrado" };
    }

    // Crear nuevo usuario con rol de alumno
    const newUser = {
      ...userData,
      role: "alumno",
      fechaRegistro: new Date().toISOString(),
      activo: true,
    };

    // Agregar a la lista de usuarios
    setRegisteredUsers((prev) => [...prev, newUser]);

    return {
      success: true,
      message: "Registro exitoso. Ahora puedes iniciar sesión",
    };
  };

  // Función de login
  const login = (username, password) => {
    // Buscar usuario en los registrados
    const foundUser = registeredUsers.find(
      (user) => user.username === username && user.password === password
    );

    if (foundUser) {
      // Crear objeto de sesión sin la contraseña
      const { password: _, ...userSession } = foundUser;
      setUser(userSession);
      localStorage.setItem("user", JSON.stringify(userSession));
      return { success: true, user: userSession };
    }

    return { success: false, message: "Usuario o contraseña incorrectos" };
  };

  // Logout
  const logout = () => {
    setUser(null);
    localStorage.removeItem("user");
  };

  // Obtener todos los alumnos (para el panel admin)
  const getAlumnos = () => {
    return registeredUsers.filter((user) => user.role === "alumno");
  };

  // Mantener sesión en recargas
  useEffect(() => {
    const savedUser = localStorage.getItem("user");
    if (savedUser) {
      try {
        setUser(JSON.parse(savedUser));
      } catch (error) {
        localStorage.removeItem("user");
      }
    }
  }, []);

  return (
    <AuthContext.Provider
      value={{
        user,
        login,
        register,
        logout,
        getAlumnos,
        registeredUsers,
      }}
    >
      {children}
    </AuthContext.Provider>
  );
};

import React, { useState, useEffect } from "react";
import { useAuth } from "../context/AuthContext";
import Alumnos from "../components/Alumnos";

const Admin = () => {
  const { user, logout } = useAuth();
  const [activeSection, setActiveSection] = useState("alumnos");
  const [alumnosData, setAlumnosData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [stats, setStats] = useState({
    total: 0,
    activos: 0,
    inactivos: 0,
  });

  useEffect(() => {
    cargarDatosAlumnos();
  }, []);

  useEffect(() => {
    if (activeSection === "alumnos" && alumnosData.length === 0) {
      cargarDatosAlumnos();
    }
  }, [activeSection]);

  const cargarDatosAlumnos = async () => {
    setLoading(true);
    try {
      const response = await fetch('/data/alumnos.json');
      
      if (!response.ok) {
        throw new Error(`Error HTTP! estado: ${response.status}`);
      }

      const data = await response.json();

      const alumnosProcesados = data.map((alumno) => ({
        ...alumno,
        role: alumno.role || "alumno",
        estado: alumno.estado || "activo",
      }));

      setAlumnosData(alumnosProcesados);
      calcularEstadisticas(alumnosProcesados);
      
    } catch (error) {
      console.error("Error al cargar datos:", error);
      alert(
        `Error al cargar los datos. Verifica que el archivo existe en public/data/alumnos.json`
      );
    } finally {
      setLoading(false);
    }
  };

  const calcularEstadisticas = (alumnos) => {
    const alumnosFiltrados = alumnos.filter((a) => a.role === "alumno");
    const total = alumnosFiltrados.length;
    const activos = alumnosFiltrados.filter(
      (a) => a.estado === "activo"
    ).length;

    setStats({
      total,
      activos,
      inactivos: total - activos,
    });
  };

  const exportarDatos = () => {
    try {
      const alumnosExport = alumnosData.filter(
        (alumno) => alumno.role === "alumno"
      );

      if (alumnosExport.length === 0) {
        alert("No hay datos para exportar");
        return;
      }

      const datosJSON = JSON.stringify(alumnosExport, null, 2);

      const blob = new Blob([datosJSON], { type: "application/json" });
      const url = URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `alumnos_exportados_${new Date().toISOString().split("T")[0]}.json`;
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      URL.revokeObjectURL(url);
      
      alert(`Se exportaron ${alumnosExport.length} registros correctamente.`);
    } catch (error) {
      console.error("Error al exportar datos:", error);
      alert("Error al exportar los datos");
    }
  };

  const renderContent = () => {
    switch (activeSection) {
      case "alumnos":
        return (
          <Alumnos
            datosAlumnos={alumnosData.filter((a) => a.role === "alumno")}
          />
        );
      case "estadisticas":
        return (
          <div className="card shadow">
            <div className="card-body">
              <h5 className="card-title text-danger">
                <i className="bi bi-bar-chart-fill me-2"></i>
                Estadísticas de Alumnos
              </h5>

              <div className="row mt-4">
                <div className="col-md-4 mb-3">
                  <div className="card bg-primary text-white">
                    <div className="card-body text-center">
                      <h3 className="card-title">{stats.total}</h3>
                      <p className="card-text">Total de Alumnos</p>
                    </div>
                  </div>
                </div>

                <div className="col-md-4 mb-3">
                  <div className="card bg-success text-white">
                    <div className="card-body text-center">
                      <h3 className="card-title">{stats.activos}</h3>
                      <p className="card-text">Alumnos Activos</p>
                    </div>
                  </div>
                </div>

                <div className="col-md-4 mb-3">
                  <div className="card bg-warning text-white">
                    <div className="card-body text-center">
                      <h3 className="card-title">{stats.inactivos}</h3>
                      <p className="card-text">Alumnos Inactivos</p>
                    </div>
                  </div>
                </div>
              </div>

              {/* Estadísticas adicionales */}
              <div className="row mt-3">
                <div className="col-md-6">
                  <div className="card">
                    <div className="card-body">
                      <h6>Información de credenciales</h6>
                      <ul className="list-group list-group-flush">
                        <li className="list-group-item d-flex justify-content-between">
                          <span>Contraseñas visibles:</span>
                          <span className="badge bg-success">{stats.total}</span>
                        </li>
                        <li className="list-group-item d-flex justify-content-between">
                          <span>Usuarios únicos:</span>
                          <span className="badge bg-info">{stats.total}</span>
                        </li>
                      </ul>
                    </div>
                  </div>
                </div>
                <div className="col-md-6">
                  <div className="card">
                    <div className="card-body">
                      <h6>Acciones disponibles</h6>
                      <button
                        className="btn btn-outline-primary w-100 mb-2"
                        onClick={exportarDatos}
                        disabled={alumnosData.length === 0}
                      >
                        <i className="bi bi-download me-2"></i>
                        Exportar todos los datos
                      </button>
                      <button
                        className="btn btn-outline-danger w-100"
                        onClick={cargarDatosAlumnos}
                      >
                        <i className="bi bi-arrow-clockwise me-2"></i>
                        Actualizar datos
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </div>
        );
      case "configuracion":
        return (
          <div className="card shadow">
            <div className="card-body">
              <h5 className="card-title text-danger">
                <i className="bi bi-gear-fill me-2"></i>
                Configuración del Sistema
              </h5>

              <div className="alert alert-warning">
                <h6>
                  <i className="bi bi-shield-exclamation me-2"></i>
                  Advertencia de seguridad
                </h6>
                <p>
                  Como administrador, tienes acceso completo a las credenciales de todos los alumnos.
                  Esta información es altamente sensible. Asegúrate de:
                </p>
                <ul>
                  <li>No compartir estas credenciales</li>
                  <li>Mantener la sesión cerrada cuando no la uses</li>
                  <li>Usar una contraseña fuerte para tu cuenta de administrador</li>
                </ul>
              </div>

              <div className="mt-4">
                <h6>Acciones de administrador</h6>
                <div className="d-grid gap-2">
                  <button
                    className="btn btn-outline-primary"
                    onClick={exportarDatos}
                    disabled={alumnosData.length === 0}
                  >
                    <i className="bi bi-download me-2"></i>
                    Exportar Datos a JSON (incluye contraseñas)
                  </button>

                  <button
                    className="btn btn-outline-success"
                    onClick={cargarDatosAlumnos}
                  >
                    <i className="bi bi-arrow-clockwise me-2"></i>
                    Recargar Datos
                  </button>
                </div>
              </div>

              <div className="mt-4">
                <h6>Información del sistema</h6>
                <ul className="list-group">
                  <li className="list-group-item d-flex justify-content-between">
                    <span>Administrador actual:</span>
                    <span className="badge bg-danger">{user.username}</span>
                  </li>
                  <li className="list-group-item d-flex justify-content-between">
                    <span>Alumnos con acceso visible:</span>
                    <span className="badge bg-success">{stats.total}</span>
                  </li>
                  <li className="list-group-item d-flex justify-content-between">
                    <span>Privilegios:</span>
                    <span className="badge bg-warning">Ver contraseñas</span>
                  </li>
                </ul>
              </div>
            </div>
          </div>
        );
      default:
        return (
          <Alumnos
            datosAlumnos={alumnosData.filter((a) => a.role === "alumno")}
          />
        );
    }
  };

  return (
    <div className="container-fluid py-4">
      <div className="row">
        {/* Sidebar */}
        <div className="col-md-3 col-lg-2 bg-dark text-white vh-100 position-fixed sidebar">
          <div className="p-3">
            <div className="text-center mb-4">
              <h4 className="text-danger mb-1">
                <i className="bi bi-shield-lock me-2"></i>
                Admin
              </h4>
              <small className="text-light">Acceso completo</small>
            </div>

            <div className="user-info mb-4 p-3 bg-dark rounded">
              <div className="d-flex align-items-center">
                <div className="bg-danger rounded-circle p-2 me-3">
                  <i className="bi bi-person-fill text-white"></i>
                </div>
                <div>
                  <p className="mb-0 text-light fw-semibold">{user.username}</p>
                  <small className="text-muted">Administrador</small>
                  <small className="d-block text-warning">
                    <i className="bi bi-key me-1"></i>
                    Ver contraseñas
                  </small>
                </div>
              </div>
            </div>

            <nav className="nav flex-column">
              <button
                className={`nav-link text-white text-start mb-2 rounded ${
                  activeSection === "alumnos" ? "bg-danger" : "hover-bg"
                }`}
                onClick={() => setActiveSection("alumnos")}
              >
                <i className="bi bi-people-fill me-2"></i>
                Alumnos
                <span className="badge bg-light text-dark ms-2">
                  {stats.total}
                </span>
              </button>

              <button
                className={`nav-link text-white text-start mb-2 rounded ${
                  activeSection === "estadisticas" ? "bg-danger" : "hover-bg"
                }`}
                onClick={() => setActiveSection("estadisticas")}
              >
                <i className="bi bi-bar-chart-fill me-2"></i>
                Estadísticas
              </button>

              <button
                className={`nav-link text-white text-start mb-2 rounded ${
                  activeSection === "configuracion" ? "bg-danger" : "hover-bg"
                }`}
                onClick={() => setActiveSection("configuracion")}
              >
                <i className="bi bi-gear-fill me-2"></i>
                Configuración
              </button>

              <hr className="text-light my-4" />

              <button
                className="btn btn-outline-light w-100 mt-2"
                onClick={logout}
              >
                <i className="bi bi-box-arrow-right me-2"></i>
                Cerrar sesión
              </button>
            </nav>

            <div className="mt-5 pt-3 border-top border-secondary">
              <small className="text-muted">
                <i className="bi bi-eye-fill me-1"></i>
                Permisos: Ver todas las contraseñas
              </small>
            </div>
          </div>
        </div>

        {/* Main Content */}
        <div className="col-md-9 col-lg-10 ms-auto">
          <div className="p-4">
            {/* Header */}
            <div className="d-flex justify-content-between align-items-center mb-4">
              <div>
                <h2 className="text-danger mb-0">
                  {activeSection === "alumnos" && (
                    <>
                      <i className="bi bi-people-fill me-2"></i>
                      Gestión de Alumnos
                    </>
                  )}
                  {activeSection === "estadisticas" && (
                    <>
                      <i className="bi bi-bar-chart-fill me-2"></i>
                      Estadísticas
                    </>
                  )}
                  {activeSection === "configuracion" && (
                    <>
                      <i className="bi bi-gear-fill me-2"></i>
                      Configuración
                    </>
                  )}
                </h2>
                <p className="text-muted mb-0">
                  {activeSection === "alumnos" &&
                    "Visualización completa de datos, incluyendo credenciales"}
                  {activeSection === "estadisticas" &&
                    "Estadísticas y análisis de los alumnos"}
                  {activeSection === "configuracion" &&
                    "Configuración del sistema y privilegios de administrador"}
                </p>
              </div>

              {activeSection === "alumnos" && (
                <div className="d-flex gap-2">
                  <button
                    className="btn btn-outline-danger"
                    onClick={cargarDatosAlumnos}
                    disabled={loading}
                    title="Recargar datos"
                  >
                    {loading ? (
                      <>
                        <span className="spinner-border spinner-border-sm me-2"></span>
                        Cargando...
                      </>
                    ) : (
                      <>
                        <i className="bi bi-arrow-clockwise me-2"></i>
                        Recargar
                      </>
                    )}
                  </button>

                  <button
                    className="btn btn-danger"
                    onClick={exportarDatos}
                    disabled={alumnosData.length === 0}
                    title="Exportar con contraseñas"
                  >
                    <i className="bi bi-download me-2"></i>
                    Exportar
                  </button>
                </div>
              )}
            </div>

            {/* Contenido principal */}
            {loading && activeSection === "alumnos" ? (
              <div className="text-center py-5">
                <div
                  className="spinner-border text-danger"
                  style={{ width: "3rem", height: "3rem" }}
                  role="status"
                >
                  <span className="visually-hidden">Cargando...</span>
                </div>
                <p className="mt-3 fs-5">Cargando datos de alumnos...</p>
              </div>
            ) : alumnosData.length === 0 && activeSection === "alumnos" ? (
              <div className="text-center py-5">
                <div className="alert alert-warning">
                  <h5>
                    <i className="bi bi-exclamation-triangle me-2"></i>
                    No hay datos de alumnos
                  </h5>
                  <p className="mb-0">
                    Asegúrate de que el archivo alumnos.json existe en public/data/
                  </p>
                  <button
                    className="btn btn-sm btn-outline-danger mt-3"
                    onClick={cargarDatosAlumnos}
                  >
                    <i className="bi bi-arrow-clockwise me-1"></i>
                    Intentar cargar nuevamente
                  </button>
                </div>
              </div>
            ) : (
              renderContent()
            )}

            {/* Información de sistema */}
            <div className="mt-5 pt-4 border-top">
              <div className="d-flex justify-content-between align-items-center">
                <small className="text-muted">
                  <i className="bi bi-shield-fill-check me-1"></i>
                  Modo administrador - Ver contraseñas habilitado
                </small>
                <small className="text-muted">
                  <i className="bi bi-clock me-1"></i>
                  {new Date().toLocaleTimeString()}
                </small>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Admin;

import React, { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom";
import { useAuth } from "../context/AuthContext";

const Login = () => {
  const { login, register } = useAuth();
  const navigate = useNavigate();
  
  // Estados del formulario
  const [isRegister, setIsRegister] = useState(false);
  const [formData, setFormData] = useState({
    username: "",
    password: "",
    nombre: "",
    apellido: "",
    dni: "",
    email: "",
    telefono: ""
  });
  const [confirmPassword, setConfirmPassword] = useState("");
  const [errors, setErrors] = useState({});
  const [touched, setTouched] = useState({});
  const [validFields, setValidFields] = useState({});
  const [loading, setLoading] = useState(false);
  const [submitMessage, setSubmitMessage] = useState({ type: '', text: '' });
  
  // Referencias para animaciones
  const formRef = useRef(null);

  // Expresiones regulares para validaciones
  const validations = {
    username: /^[a-zA-Z0-9_]{4,20}$/,
    password: /^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])[A-Za-z\d@$!%*?&]{8,}$/,
    nombre: /^[a-zA-ZÁÉÍÓÚáéíóúñÑ\s]{2,50}$/,
    apellido: /^[a-zA-ZÁÉÍÓÚáéíóúñÑ\s]{2,50}$/,
    dni: /^\d{7,8}$/,
    email: /^[^\s@]+@[^\s@]+\.[^\s@]+$/,
    telefono: /^(\d{10,15})?$/
  };

  // Validaciones en tiempo real
  useEffect(() => {
    validateForm();
  }, [formData, confirmPassword]);

  const validateField = (name, value) => {
    if (!touched[name]) return true; // No validar hasta que se toque
    
    switch (name) {
      case 'username':
        return validations.username.test(value);
      case 'password':
        if (isRegister) {
          return validations.password.test(value);
        }
        return value.length >= 1;
      case 'nombre':
        return validations.nombre.test(value);
      case 'apellido':
        return validations.apellido.test(value);
      case 'dni':
        return validations.dni.test(value);
      case 'email':
        return validations.email.test(value);
      case 'telefono':
        return !value || validations.telefono.test(value);
      case 'confirmPassword':
        return formData.password === confirmPassword;
      default:
        return true;
    }
  };

  const validateForm = () => {
    const newErrors = {};
    const newValidFields = {};

    // Validaciones comunes
    if (touched.username) {
      if (!formData.username.trim()) {
        newErrors.username = "El usuario es requerido";
      } else if (!validations.username.test(formData.username)) {
        newErrors.username = "Usuario inválido (4-20 caracteres, solo letras, números y _)";
      } else {
        newValidFields.username = true;
      }
    }

    if (touched.password) {
      if (!formData.password.trim()) {
        newErrors.password = "La contraseña es requerida";
      } else if (isRegister && !validations.password.test(formData.password)) {
        newErrors.password = "Mínimo 8 caracteres, 1 mayúscula, 1 minúscula, 1 número y 1 caracter especial";
      } else {
        newValidFields.password = true;
      }
    }

    // Validaciones específicas de registro
    if (isRegister) {
      if (touched.nombre) {
        if (!formData.nombre.trim()) {
          newErrors.nombre = "El nombre es requerido";
        } else if (!validations.nombre.test(formData.nombre)) {
          newErrors.nombre = "Nombre inválido (solo letras y espacios)";
        } else {
          newValidFields.nombre = true;
        }
      }

      if (touched.apellido) {
        if (!formData.apellido.trim()) {
          newErrors.apellido = "El apellido es requerido";
        } else if (!validations.apellido.test(formData.apellido)) {
          newErrors.apellido = "Apellido inválido (solo letras y espacios)";
        } else {
          newValidFields.apellido = true;
        }
      }

      if (touched.dni) {
        if (!formData.dni.trim()) {
          newErrors.dni = "El DNI es requerido";
        } else if (!validations.dni.test(formData.dni)) {
          newErrors.dni = "DNI inválido (7 u 8 dígitos)";
        } else {
          newValidFields.dni = true;
        }
      }

      if (touched.email) {
        if (!formData.email.trim()) {
          newErrors.email = "El email es requerido";
        } else if (!validations.email.test(formData.email)) {
          newErrors.email = "Email inválido";
        } else {
          newValidFields.email = true;
        }
      }

      if (touched.telefono && formData.telefono) {
        if (!validations.telefono.test(formData.telefono)) {
          newErrors.telefono = "Teléfono inválido (10-15 dígitos)";
        } else {
          newValidFields.telefono = true;
        }
      }

      if (touched.confirmPassword) {
        if (!confirmPassword.trim()) {
          newErrors.confirmPassword = "Confirma tu contraseña";
        } else if (formData.password !== confirmPassword) {
          newErrors.confirmPassword = "Las contraseñas no coinciden";
        } else {
          newValidFields.confirmPassword = true;
        }
      }
    }

    setErrors(newErrors);
    setValidFields(newValidFields);
    return Object.keys(newErrors).length === 0;
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    
    // Limpieza de datos según el campo
    let cleanedValue = value;
    
    switch (name) {
      case 'dni':
        cleanedValue = value.replace(/\D/g, '').slice(0, 8);
        break;
      case 'telefono':
        cleanedValue = value.replace(/\D/g, '').slice(0, 15);
        break;
      case 'username':
        cleanedValue = value.toLowerCase().replace(/[^a-z0-9_]/g, '');
        break;
      case 'email':
        cleanedValue = value.toLowerCase();
        break;
      case 'nombre':
      case 'apellido':
        cleanedValue = value.replace(/[^a-zA-ZÁÉÍÓÚáéíóúñÑ\s]/g, '');
        break;
    }
    
    setFormData(prev => ({
      ...prev,
      [name]: cleanedValue
    }));
    
    // Marcar como tocado cuando se empieza a escribir
    if (!touched[name]) {
      setTouched(prev => ({ ...prev, [name]: true }));
    }
  };

  const handleBlur = (field) => {
    setTouched(prev => ({ ...prev, [field]: true }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setSubmitMessage({ type: '', text: '' });
    
    // Marcar todos los campos como tocados
    const allFields = isRegister 
      ? ['username', 'password', 'nombre', 'apellido', 'dni', 'email', 'telefono', 'confirmPassword']
      : ['username', 'password'];
    
    const newTouched = allFields.reduce((acc, field) => ({ ...acc, [field]: true }), {});
    setTouched(newTouched);
    
    // Esperar un ciclo para que se actualice el estado
    setTimeout(() => {
      if (!validateForm()) {
        setLoading(false);
        setSubmitMessage({ type: 'error', text: 'Por favor, corrige los errores en el formulario' });
        
        // Enfocar el primer campo con error
        const firstErrorField = Object.keys(errors)[0];
        if (firstErrorField && formRef.current) {
          const errorInput = formRef.current.querySelector(`[name="${firstErrorField}"]`);
          if (errorInput) errorInput.focus();
        }
        return;
      }

      proceedWithSubmit();
    }, 0);
  };

  const proceedWithSubmit = async () => {
    try {
      if (isRegister) {
        // Proceso de registro
        const result = register(formData);
        if (result.success) {
          setSubmitMessage({ type: 'success', text: result.message });
          // Limpiar formulario
          setFormData({
            username: "",
            password: "",
            nombre: "",
            apellido: "",
            dni: "",
            email: "",
            telefono: ""
          });
          setConfirmPassword("");
          setTouched({});
          setValidFields({});
          // Cambiar a modo login después de 2 segundos
          setTimeout(() => {
            setIsRegister(false);
            setSubmitMessage({ type: '', text: '' });
          }, 2000);
        } else {
          setSubmitMessage({ type: 'error', text: result.message });
        }
      } else {
        // Proceso de login
        const result = login(formData.username, formData.password);
        if (result.success) {
          setSubmitMessage({ type: 'success', text: 'Inicio de sesión exitoso. Redirigiendo...' });
          
          // Redirigir según el rol
          setTimeout(() => {
            if (result.user.role === 'admin') {
              navigate("/admin");
            } else {
              navigate("/alumno");
            }
          }, 1500);
        } else {
          setSubmitMessage({ type: 'error', text: result.message });
        }
      }
    } catch (error) {
      setSubmitMessage({ 
        type: 'error', 
        text: 'Ocurrió un error inesperado. Por favor, intenta nuevamente' 
      });
    } finally {
      setLoading(false);
    }
  };

  const toggleMode = () => {
    setIsRegister(!isRegister);
    setSubmitMessage({ type: '', text: '' });
    setErrors({});
    setTouched({});
    setValidFields({});
    setConfirmPassword("");
  };

  // Función para renderizar el ícono de validación
  const renderValidationIcon = (fieldName) => {
    if (!touched[fieldName]) return null;
    
    if (errors[fieldName]) {
      return (
        <div className="input-group-append">
          <span className="input-group-text bg-white border-start-0 text-danger">
            <i className="bi bi-x-circle-fill"></i>
          </span>
        </div>
      );
    }
    
    if (validFields[fieldName]) {
      return (
        <div className="input-group-append">
          <span className="input-group-text bg-white border-start-0 text-success">
            <i className="bi bi-check-circle-fill"></i>
          </span>
        </div>
      );
    }
    
    return null;
  };

  // Función para obtener clase del campo
  const getInputClassName = (field) => {
    let className = "form-control ";
    
    if (touched[field]) {
      if (errors[field]) {
        className += "is-invalid ";
      } else if (validFields[field]) {
        className += "is-valid ";
      }
    }
    
    return className.trim();
  };

  // Función para renderizar mensaje de ayuda
  const renderHelpText = (field) => {
    if (!touched[field] || validFields[field]) return null;
    
    const helpTexts = {
      username: "4-20 caracteres, solo letras, números y _",
      password: "Mín. 8 caracteres con mayúscula, minúscula, número y símbolo (@$!%*?&)",
      nombre: "Solo letras y espacios (2-50 caracteres)",
      apellido: "Solo letras y espacios (2-50 caracteres)",
      dni: "7 u 8 dígitos",
      email: "Formato: usuario@dominio.com",
      telefono: "10-15 dígitos (opcional)",
      confirmPassword: "Debe coincidir con la contraseña"
    };
    
    if (helpTexts[field]) {
      return <small className="form-text text-muted">{helpTexts[field]}</small>;
    }
    
    return null;
  };

  return (
    <div className="d-flex align-items-center justify-content-center min-vh-100 bg-gradient">
      <div className="card p-4 shadow-lg border-0" style={{ width: "450px", maxWidth: "95%" }} ref={formRef}>
        <div className="text-center mb-4">
          <h2 className="text-danger fw-bold">
            <i className={`bi bi-${isRegister ? 'person-plus' : 'box-arrow-in-right'} me-2`}></i>
            {isRegister ? "Crear Cuenta" : "Iniciar Sesión"}
          </h2>
          <p className="text-muted">
            {isRegister 
              ? "Completa el formulario para registrarte" 
              : "Ingresa tus credenciales para acceder"}
          </p>
        </div>

        {/* Indicador de progreso (solo para registro) */}
        {isRegister && (
          <div className="mb-4">
            <div className="d-flex justify-content-between align-items-center mb-2">
              <small className="text-muted">Progreso del formulario:</small>
              <small className="fw-semibold text-danger">
                {Object.keys(validFields).length} / 7 campos válidos
              </small>
            </div>
            <div className="progress" style={{ height: "6px" }}>
              <div 
                className="progress-bar bg-success" 
                role="progressbar" 
                style={{ width: `${(Object.keys(validFields).length / 7) * 100}%` }}
                aria-valuenow={Object.keys(validFields).length}
                aria-valuemin="0"
                aria-valuemax="7"
              ></div>
            </div>
          </div>
        )}

        {/* Mensajes de éxito/error */}
        {submitMessage.text && (
          <div className={`alert alert-${submitMessage.type === 'success' ? 'success' : 'danger'} alert-dismissible fade show`}>
            <i className={`bi bi-${submitMessage.type === 'success' ? 'check-circle' : 'exclamation-triangle'} me-2`}></i>
            {submitMessage.text}
            <button type="button" className="btn-close" onClick={() => setSubmitMessage({ type: '', text: '' })}></button>
          </div>
        )}

        <form onSubmit={handleSubmit} noValidate>
          {/* Usuario */}
          <div className="mb-3">
            <label className="form-label fw-semibold">
              <i className="bi bi-person me-1"></i>
              Usuario *
            </label>
            <div className="input-group">
              <input
                type="text"
                className={getInputClassName('username')}
                name="username"
                value={formData.username}
                onChange={handleInputChange}
                onBlur={() => handleBlur('username')}
                placeholder="ej: juan.perez"
                disabled={loading}
                required
              />
              {renderValidationIcon('username')}
            </div>
            {touched.username && errors.username ? (
              <div className="invalid-feedback d-block">{errors.username}</div>
            ) : (
              renderHelpText('username')
            )}
          </div>

          {/* Contraseña */}
          <div className="mb-3">
            <label className="form-label fw-semibold">
              <i className="bi bi-lock me-1"></i>
              Contraseña *
            </label>
            <div className="input-group">
              <input
                type="password"
                className={getInputClassName('password')}
                name="password"
                value={formData.password}
                onChange={handleInputChange}
                onBlur={() => handleBlur('password')}
                placeholder={isRegister ? "Contraseña segura" : "Tu contraseña"}
                disabled={loading}
                required
              />
              {renderValidationIcon('password')}
            </div>
            {touched.password && errors.password ? (
              <div className="invalid-feedback d-block">{errors.password}</div>
            ) : (
              renderHelpText('password')
            )}
            
            {/* Indicador de fortaleza de contraseña (solo registro) */}
            {isRegister && touched.password && (
              <div className="mt-2">
                <small className="d-block mb-1">Fortaleza de contraseña:</small>
                <div className="password-strength">
                  {['Mínimo 8 caracteres', 'Mayúscula y minúscula', 'Al menos un número', 'Carácter especial'].map((req, idx) => {
                    const regexChecks = [
                      /.{8,}/,
                      /(?=.*[a-z])(?=.*[A-Z])/,
                      /\d/,
                      /[@$!%*?&]/
                    ];
                    const isValid = regexChecks[idx].test(formData.password);
                    
                    return (
                      <div key={idx} className="d-flex align-items-center mb-1">
                        <i className={`bi ${isValid ? 'bi-check-circle-fill text-success' : 'bi-circle text-muted'} me-2`}></i>
                        <small className={isValid ? 'text-success' : 'text-muted'}>{req}</small>
                      </div>
                    );
                  })}
                </div>
              </div>
            )}
          </div>

          {/* Campos de registro */}
          {isRegister && (
            <>
              {/* Nombre y Apellido */}
              <div className="row">
                <div className="col-md-6 mb-3">
                  <label className="form-label fw-semibold">
                    <i className="bi bi-card-heading me-1"></i>
                    Nombre *
                  </label>
                  <div className="input-group">
                    <input
                      type="text"
                      className={getInputClassName('nombre')}
                      name="nombre"
                      value={formData.nombre}
                      onChange={handleInputChange}
                      onBlur={() => handleBlur('nombre')}
                      placeholder="Juan"
                      disabled={loading}
                      required
                    />
                    {renderValidationIcon('nombre')}
                  </div>
                  {touched.nombre && errors.nombre ? (
                    <div className="invalid-feedback d-block">{errors.nombre}</div>
                  ) : (
                    renderHelpText('nombre')
                  )}
                </div>
                <div className="col-md-6 mb-3">
                  <label className="form-label fw-semibold">
                    <i className="bi bi-card-heading me-1"></i>
                    Apellido *
                  </label>
                  <div className="input-group">
                    <input
                      type="text"
                      className={getInputClassName('apellido')}
                      name="apellido"
                      value={formData.apellido}
                      onChange={handleInputChange}
                      onBlur={() => handleBlur('apellido')}
                      placeholder="Pérez"
                      disabled={loading}
                      required
                    />
                    {renderValidationIcon('apellido')}
                  </div>
                  {touched.apellido && errors.apellido ? (
                    <div className="invalid-feedback d-block">{errors.apellido}</div>
                  ) : (
                    renderHelpText('apellido')
                  )}
                </div>
              </div>

              {/* DNI */}
              <div className="mb-3">
                <label className="form-label fw-semibold">
                  <i className="bi bi-credit-card me-1"></i>
                  DNI *
                </label>
                <div className="input-group">
                  <input
                    type="text"
                    className={getInputClassName('dni')}
                    name="dni"
                    value={formData.dni}
                    onChange={handleInputChange}
                    onBlur={() => handleBlur('dni')}
                    placeholder="12345678"
                    maxLength="8"
                    disabled={loading}
                    required
                  />
                  {renderValidationIcon('dni')}
                </div>
                {touched.dni && errors.dni ? (
                  <div className="invalid-feedback d-block">{errors.dni}</div>
                ) : (
                  renderHelpText('dni')
                )}
              </div>

              {/* Email */}
              <div className="mb-3">
                <label className="form-label fw-semibold">
                  <i className="bi bi-envelope me-1"></i>
                  Email *
                </label>
                <div className="input-group">
                  <input
                    type="email"
                    className={getInputClassName('email')}
                    name="email"
                    value={formData.email}
                    onChange={handleInputChange}
                    onBlur={() => handleBlur('email')}
                    placeholder="juan@email.com"
                    disabled={loading}
                    required
                  />
                  {renderValidationIcon('email')}
                </div>
                {touched.email && errors.email ? (
                  <div className="invalid-feedback d-block">{errors.email}</div>
                ) : (
                  renderHelpText('email')
                )}
              </div>

              {/* Teléfono (opcional) */}
              <div className="mb-3">
                <label className="form-label fw-semibold">
                  <i className="bi bi-telephone me-1"></i>
                  Teléfono
                </label>
                <div className="input-group">
                  <input
                    type="text"
                    className={getInputClassName('telefono')}
                    name="telefono"
                    value={formData.telefono}
                    onChange={handleInputChange}
                    onBlur={() => handleBlur('telefono')}
                    placeholder="1122334455"
                    disabled={loading}
                  />
                  {renderValidationIcon('telefono')}
                </div>
                {touched.telefono && errors.telefono ? (
                  <div className="invalid-feedback d-block">{errors.telefono}</div>
                ) : (
                  renderHelpText('telefono')
                )}
              </div>

              {/* Confirmar Contraseña */}
              <div className="mb-4">
                <label className="form-label fw-semibold">
                  <i className="bi bi-lock-fill me-1"></i>
                  Confirmar Contraseña *
                </label>
                <div className="input-group">
                  <input
                    type="password"
                    className={`form-control ${touched.confirmPassword && errors.confirmPassword ? 'is-invalid' : ''} ${touched.confirmPassword && !errors.confirmPassword ? 'is-valid' : ''}`}
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    onBlur={() => handleBlur('confirmPassword')}
                    placeholder="Repite tu contraseña"
                    disabled={loading}
                    required
                  />
                  {renderValidationIcon('confirmPassword')}
                </div>
                {touched.confirmPassword && errors.confirmPassword ? (
                  <div className="invalid-feedback d-block">{errors.confirmPassword}</div>
                ) : (
                  renderHelpText('confirmPassword')
                )}
                
                {/* Indicador de coincidencia */}
                {touched.confirmPassword && formData.password && confirmPassword && (
                  <div className="mt-1">
                    {formData.password === confirmPassword ? (
                      <small className="text-success">
                        <i className="bi bi-check-circle-fill me-1"></i>
                        Las contraseñas coinciden
                      </small>
                    ) : (
                      <small className="text-danger">
                        <i className="bi bi-x-circle-fill me-1"></i>
                        Las contraseñas no coinciden
                      </small>
                    )}
                  </div>
                )}
              </div>
            </>
          )}

          {/* Botón de envío */}
          <button 
            type="submit" 
            className="btn btn-danger w-100 py-2 mb-3 fw-semibold"
            disabled={loading}
          >
            {loading ? (
              <>
                <span className="spinner-border spinner-border-sm me-2"></span>
                {isRegister ? "Registrando..." : "Iniciando sesión..."}
              </>
            ) : (
              <>
                <i className={`bi bi-${isRegister ? 'person-plus' : 'box-arrow-in-right'} me-2`}></i>
                {isRegister ? "Registrarse" : "Iniciar Sesión"}
              </>
            )}
          </button>

          {/* Enlace para cambiar modo */}
          <div className="text-center">
            <button
              type="button"
              className="btn btn-link text-decoration-none"
              onClick={toggleMode}
              disabled={loading}
            >
              <i className={`bi bi-arrow-${isRegister ? 'left' : 'right'}-circle me-1`}></i>
              {isRegister 
                ? "¿Ya tienes cuenta? Inicia sesión" 
                : "¿No tienes cuenta? Regístrate"}
            </button>
          </div>
        </form>

        {/* Información adicional */}
        <div className="mt-4 pt-3 border-top">
          <div className="d-flex align-items-center">
            <i className="bi bi-info-circle text-primary me-2"></i>
            <small className="text-muted">
              <strong>Nota:</strong> * Campos obligatorios
            </small>
          </div>
          <div className="mt-2">
            <small className="text-muted">
              {isRegister 
                ? "✓ Tus datos están protegidos" 
                : "🔒 Acceso seguro con validación en tiempo real"}
            </small>
          </div>
          
          {/* Indicadores de validación */}
          <div className="mt-3 d-flex justify-content-around small">
            <div className="text-center">
              <i className="bi bi-check-circle-fill text-success d-block"></i>
              <small className="text-muted">Válido</small>
            </div>
            <div className="text-center">
              <i className="bi bi-x-circle-fill text-danger d-block"></i>
              <small className="text-muted">Error</small>
            </div>
            <div className="text-center">
              <i className="bi bi-dash-circle text-muted d-block"></i>
              <small className="text-muted">Pendiente</small>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
